import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // The result should not be the same instance as baseFormat
        assertNotSame(baseFormat, resultFormat);

        // The result should have header set (not null)
        assertNotNull(resultFormat.getHeader());

        // The result should have skipHeaderRecord set to true
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The header from resultFormat should be the same as from withHeader() on baseFormat
        CSVFormat headerFormat = baseFormat.withHeader();
        assertArrayEquals(headerFormat.getHeader(), resultFormat.getHeader());

        // The skipHeaderRecord should be true in resultFormat, false in headerFormat
        assertFalse(headerFormat.getSkipHeaderRecord());
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The other properties should remain equal
        assertEquals(headerFormat.getDelimiter(), resultFormat.getDelimiter());
        assertEquals(headerFormat.getQuoteCharacter(), resultFormat.getQuoteCharacter());
        assertEquals(headerFormat.getRecordSeparator(), resultFormat.getRecordSeparator());
    }
}
